const body = $input.first().json.body ?? $input.first().json;
const message = String(body.message || '').trim();
const userId = String(body.user_id || 'unknown');
const userName = String(body.user_name || '');
const sessionId = String(body.session_id || '');
const history = Array.isArray(body.history) ? body.history : [];
const norm = message.toLowerCase();

const escalatePhrases = ['talk to human','speak to a human','human support','real person','support agent','customer support','kaluba','speak to someone','talk to someone'];
const unsatisfiedPhrases = ['not satisfied','unsatisfied','not happy','unhappy with','this is useless','waste of time'];
const contactPhrases = ['contact admin','contact support','support email','support phone','how do i contact','how to contact','what\'s your email','what is your email'];
const callbackPhrases = ['call me back','contact me back','reach out to me','get back to me'];

function ticketId() {
  return 'ZD-' + Math.random().toString(16).slice(2, 10).toUpperCase();
}
function containsAny(text, list) { return list.some(p => text.includes(p)); }
function isEscalate(text) {
  if (containsAny(text, contactPhrases) && !containsAny(text, callbackPhrases) && !containsAny(text, escalatePhrases)) return false;
  return containsAny(text, escalatePhrases) || /\b(support|agent)\b/i.test(text);
}

function pricing() {
  return 'ZedApply plans (ZMW/month):\n• Free — K0, 10 matches/mo\n• Starter — K125, 50 matches/mo (no tailored CV)\n• Professional — K250, 125 matches/mo (+ cover letters + tailored CVs)\n• Super Standard — K500, unlimited matches + Bwana Interview\nUpgrade at /pricing. Pay with MTN/Airtel (Lenco) or card (DPO).';
}

let source = 'llm';
let response = '';
let escalation_ticket_id = '';

if (!message) {
  return [{ json: { user_id: userId, user_name: userName, session_id: sessionId, message, history, source: 'faq', response: 'Please type a question.', took_ms: 0, escalate: false } }];
}

if (containsAny(norm, contactPhrases) && !containsAny(norm, callbackPhrases) && !containsAny(norm, escalatePhrases)) {
  source = 'faq';
  response = 'Contact ZedApply Support: email support@zedapply.com or call +260971234567. We aim to respond within 24 hours on business days.';
} else if (containsAny(norm, unsatisfiedPhrases) || isEscalate(norm)) {
  escalation_ticket_id = ticketId();
  source = 'escalated';
  response = "I've flagged this for ZedApply Support (ref " + escalation_ticket_id + "). We'll follow up within 24 hours.";
} else if (norm.includes('starter') && !norm.includes('professional')) {
  source = 'faq';
  response = 'Starter: K125/mo, 50 matches. Advanced CV analysis — tailored CVs start on Professional. See /pricing.';
} else if (norm.includes('price') || norm.includes('pricing') || norm.includes('cost') || norm.includes('how much') || norm.includes('k125') || norm.includes('k250') || norm.includes('k500')) {
  source = 'faq'; response = pricing();
} else if (norm.includes('how do i apply') || norm.includes('how to apply')) {
  source = 'faq'; response = 'Upload your CV on /profile, then check /matches. Reply to your WhatsApp digest (07:00) with 1–5 for job details.';
} else if (norm.includes('cancel') || norm.includes('unsubscribe')) {
  source = 'faq'; response = 'Manage your plan in /settings → Subscription. Type "talk to human" for billing help.';
} else if (norm.includes('where is my cv') || norm.includes('my cv') || norm.includes('upload cv')) {
  source = 'faq'; response = 'Your CV is on /profile → CV & Skills. Upload PDF or DOCX there.';
} else if (norm.includes('match') && (norm.includes('how') || norm.includes('work') || norm.includes('score'))) {
  source = 'faq'; response = 'Each match scores 0–100: 50% semantic + 20% skills + 15% experience + 10% location + 5% recency. Open any match to see the breakdown.';
} else if (norm.includes('refund') || norm.includes('money back')) {
  source = 'faq'; response = 'Refund within 7 days of payment if you have not generated any AI documents. Email support@zedapply.com or type "talk to human".';
}

return [{ json: { user_id: userId, user_name: userName, session_id: sessionId, message, history, source, response, took_ms: 0, escalate: source === 'escalated', escalation_ticket_id } }];

const item = $input.first().json;
let response = item.response || '';
let source = item.source || 'llm';
if (item.choices) {
  response = item.choices?.[0]?.message?.content || response;
  source = 'llm';
}
const start = item.took_ms || 0;
return [{ json: { response: String(response).trim(), source, took_ms: start, session_id: item.session_id || '' } }];
